import java.util.*;

public int[] findingUsersActiveMinutes(int[][] logs, int k) {
    Map<Integer, Set<Integer>> user_minutes = new HashMap<>();
    for (int[] log : logs) {
        user_minutes.computeIfAbsent(log[0], user -> new HashSet<>()).add(log[1]);
    }
    int[] result = new int[k];
    for (Set<Integer> minutes : user_minutes.values()) {
        if (minutes.size() <= k) {
            result[minutes.size() - 1]++;
        }
    }
    return result;
}
```


